import React, { useState } from "react";
import axios from "axios";
import "./App.css";

function App() {
  const [file, setFile] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [feedback, setFeedback] = useState("");

  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
    setResult(null);
    setError("");
  };

  const handleUpload = async () => {
    if (!file) {
      alert("Please upload a file first");
      return;
    }

    const formData = new FormData();
    formData.append("file", file);

    try {
      setLoading(true);
      setError("");

      const response = await axios.post(
        "http://localhost:8000/predict",
        formData
      );

      setResult(response.data);
    } catch (err) {
      console.error(err);
      setError("Error connecting to backend");
    } finally {
      setLoading(false);
    }
  };

  const handleFeedback = async () => {
    if (!feedback) return;

    try {
      await axios.post("http://localhost:8000/feedback", {
        feedback: feedback,
      });

      alert("Feedback submitted!");
      setFeedback("");
    } catch (err) {
      console.error(err);
      alert("Failed to submit feedback");
    }
  };

  return (
    <div className="container">
      {/* HEADER */}
      <h1 className="brand">COGNIFY</h1>
      <p className="tagline">
        Understand your lecture better. Analyze cognitive load with AI.
      </p>

      {/* UPLOAD BOX */}
      <div className="card">
        <h2>Upload Lecture Audio</h2>

        <input type="file" onChange={handleFileChange} />
        <button onClick={handleUpload}>Analyze Lecture</button>

        {/* LOADING */}
        {loading && <p className="loading">Analyzing... ⏳</p>}

        {/* ERROR */}
        {error && <p className="error">{error}</p>}
      </div>

      {/* RESULT */}
      {result && (
        <div className="result-card">
          <h2>
            Prediction:{" "}
            <span className="highlight">
              {result.prediction?.toUpperCase()}
            </span>
          </h2>

          <h3>Probability:</h3>
          <p>Low: {result.probability?.low}</p>
          <p>Medium: {result.probability?.medium}</p>
          <p>High: {result.probability?.high}</p>

          <h3>Summary:</h3>
          <p>{result.summary}</p>

          <h3>Quiz:</h3>
          <ul>
            {result.quiz?.map((q, i) => (
              <li key={i}>{q}</li>
            ))}
          </ul>

          {/* FEEDBACK */}
          <div className="feedback-box">
            <h3>Give Feedback</h3>
            <input
              type="text"
              value={feedback}
              onChange={(e) => setFeedback(e.target.value)}
              placeholder="Enter your feedback"
            />
            <button onClick={handleFeedback}>Submit Feedback</button>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
